javascript:
document.addEventListener('DOMContentLoaded', function() {
  const form = document.getElementById('lead-form');
  const msg = document.getElementById('lead-msg');
  const statusSelect = document.getElementById('lead-status');
  const convertBtn = document.getElementById('convert-btn');

  // Toggle convert button
  statusSelect.addEventListener('change', () => {
    convertBtn.style.display = (statusSelect.value === 'Converted') ? 'inline-block' : 'none';
  });

  // Save Lead
  form.addEventListener('submit', function(e) {
    e.preventDefault();
    msg.innerText = 'Submitting...';

    const data = {};
    new FormData(form).forEach((v, k) => data[k] = v);

    frappe.call({
      method: "my_webapp.api.create_or_update_lead",  // 🔁 replace your_app
      args: { payload: data },
      callback: function(r) {
        if (r.message) {
          msg.innerText = `✅ Lead ${r.message.status}: ${r.message.name}`;
          form.dataset.leadName = r.message.name;
        } else {
          msg.innerText = "⚠️ Unexpected response";
        }
      },
      error: function(err) {
        msg.innerText = '❌ Error saving Lead';
      }
    });
  });

  // Convert Lead → Prospect
  convertBtn.addEventListener('click', function() {
    const leadName = form.dataset.leadName;
    if (!leadName) {
      msg.innerText = '❌ Save the lead first!';
      return;
    }

    msg.innerText = 'Converting...';

    frappe.call({
      method: "my_webapp.api.convert_lead_to_prospect",  // 🔁 replace your_app
      args: { lead_name: leadName },
      callback: function(r) {
        if (r.message && r.message.status === 'created') {
          msg.innerHTML = `✅ Prospect created: <a href="/app/prospect/${r.message.prospect_name}" target="_blank">${r.message.prospect_name}</a>`;
        } else {
          msg.innerText = "⚠️ Conversion failed";
        }
      },
      error: function(err) {
        msg.innerText = '❌ Error converting Lead';
      }
    });
  });
});

