javascript:
document.addEventListener('DOMContentLoaded', function() {
  const form = document.getElementById('sales-order-form');
  const msg = document.getElementById('so-msg');

  form.addEventListener('submit', function(e) {
    e.preventDefault();
    msg.innerText = 'Submitting...';

    const data = {};
    new FormData(form).forEach((v, k) => data[k] = v);

    // Auto calculate Sales if empty
    if (!data.sales || data.sales === '') {
      const q = Number(data.quantity || 0);
      const u = Number(data.unit_price || 0);
      const d = Number(data.discount || 0);
      data.sales = (q * u * (1 - d)).toFixed(2);
    }

    frappe.call({
      method: "my_webapp.api.create_sales_order",   // 👈 Replace "your_app" with your app name
      args: { payload: data },
      callback: function(r) {
        if (r.message && r.message.status === 'created') {
          msg.innerHTML = `✅ Created Successfully: 
            <a href="/app/sales-order/${r.message.name}" target="_blank">${r.message.name}</a>`;
          form.reset();
        } else if (r.message && r.message.status === 'exists') {
          msg.innerHTML = `⚠️ Order already exists: ${r.message.name}`;
        } else {
          msg.innerText = '⚠️ Unexpected response';
        }
      },
      error: function(err) {
        msg.innerText = '❌ Error: ' + (err.responseText || JSON.stringify(err));
      }
    });
  });
});

