document.addEventListener("DOMContentLoaded", function () {
  // --- cached DOM nodes (safely) ---
  const leadFormContainer = document.getElementById("lead-form-container");
  const prospectFormContainer = document.getElementById("prospect-form-container");
  const convertSection = document.getElementById("convert-section");
  const leadStatus = document.getElementById("lead-status");
  const leadDropdown = document.getElementById("lead-dropdown");
  const leadNameField = document.getElementById("lead-name");


  // Sidebar toggles
  document.getElementById("lead-toggle").addEventListener("click", () => {
    const section = document.getElementById("lead-section");
    section.style.display = section.style.display === "block" ? "none" : "block";
  });
  document.getElementById("prospect-toggle").addEventListener("click", () => {
    const section = document.getElementById("prospect-section");
    section.style.display = section.style.display === "block" ? "none" : "block";
  });

  // Show convert button if status = Converted
  leadStatus.addEventListener("change", function () {
    convertSection.style.display = this.value === "Converted" ? "block" : "none";
  });


  // safe-get helper to avoid throwing if element missing
  function $id(id) { return document.getElementById(id); }

  // --- attach handlers only if the elements exist (prevents silent JS stops) ---
  const createLeadBtn = $id("create-lead-btn");
  if (createLeadBtn && leadFormContainer && prospectFormContainer) {
    createLeadBtn.addEventListener("click", () => {
      leadFormContainer.style.display = "block";
      prospectFormContainer.style.display = "none";
    });
  }

  const createProspectBtn = $id("create-prospect-btn");
  if (createProspectBtn && leadFormContainer && prospectFormContainer) {
    createProspectBtn.addEventListener("click", () => {
      leadFormContainer.style.display = "none";
      prospectFormContainer.style.display = "block";
      populateLeadDropdown(); // refresh lead list for dropdown
    });
  }

  const clearBtn = $id("clear-btn");
  if (clearBtn) {
    clearBtn.addEventListener("click", () => {
      document.querySelectorAll("input, textarea").forEach(el => el.value = "");
      document.querySelectorAll("select").forEach(el => el.selectedIndex = 0);
      if (convertSection) convertSection.style.display = "none";
    });
  }

  if (leadStatus && convertSection) {
    leadStatus.addEventListener("change", function () {
      convertSection.style.display = (this.value === "Converted") ? "block" : "none";
    });
  }

  // ----- CREATE OR UPDATE LEAD -----
  const leadForm = $id("lead-form");
  if (leadForm) {
    leadForm.addEventListener("submit", function (e) {
      e.preventDefault();
      const data = {};
      this.querySelectorAll("input, select").forEach(el => {
        if (el.name) data[el.name] = el.value;
      });

      const method = data.name ? "my_webapp.api.update_lead" : "my_webapp.api.create_lead";
      try {
        frappe.call({ method, args: { payload: data } })
          .then(function (r) {
            console.log("frappe response (create/update lead):", r);
            if (r && r.message && r.message.name) {
              const leadMsgEl = $id("lead-msg");
              if (leadMsgEl) {
                leadMsgEl.innerText =
                  data.name ? `Lead Updated: ${r.message.name}` : `Lead Created: ${r.message.name}`;
              }
              if (leadNameField) leadNameField.value = r.message.name;
              loadLeads();
              populateLeadDropdown();
            } else {
              console.warn("Unexpected create/update lead response:", r);
            }
          })
          .catch(err => console.error("frappe.call error (create/update lead):", err));
      } catch (err) {
        console.error("Exception while calling create/update lead:", err);
      }
    });
  }

  // ----- CONVERT LEAD TO PROSPECT -----
  const convertBtn = $id("convert-btn");
  if (convertBtn) {
    convertBtn.addEventListener("click", function () {
      const leadName = leadNameField ? leadNameField.value : "";
      if (!leadName) {
        const cm = $id("convert-msg");
        if (cm) cm.innerText = "Please save lead first.";
        return;
      }

      try {
        frappe.call({ method: "my_webapp.api.convert_lead_to_prospect", args: { lead_name: leadName } })
          .then(function (r) {
            console.log("frappe response (convert):", r);
            const cm = $id("convert-msg");
            if (!r || !r.message) {
              if (cm) cm.innerText = "Conversion returned no message.";
              return;
            }
            if (r.message.status === "exists") {
              if (cm) cm.innerText = `Prospect already exists: ${r.message.name}`;
            } else if (r.message.status === "created") {
              if (cm) cm.innerText = `Converted to Prospect: ${r.message.name}`;
              loadProspects();
            } else {
              if (cm) cm.innerText = r.message.msg || "Conversion failed.";
            }
          })
          .catch(err => console.error("frappe.call error (convert):", err));
      } catch (err) {
        console.error("Exception while calling convert:", err);
      }
    });
  }

  // ----- CREATE OR UPDATE PROSPECT -----
const prospectForm = $id("prospect-form");
if (prospectForm) {
  prospectForm.addEventListener("submit", function (e) {
    e.preventDefault();
    const data = {};
    this.querySelectorAll("input, select").forEach(el => {
      if (el.name) data[el.name] = el.value;
    });

    // Choose API based on whether we're updating or creating
    const method = data.name ? "my_webapp.api.update_prospect" : "my_webapp.api.create_prospect";

    try {
      frappe.call({ method, args: { payload: data } })
        .then(function (r) {
          console.log("frappe response (create/update prospect):", r);
          if (r && r.message && r.message.name) {
            const pm = $id("prospect-msg");
            if (pm) {
              pm.innerText = data.name
                ? `Prospect Updated: ${r.message.name}`
                : `Prospect Created: ${r.message.name}`;
            }
            loadProspects();
          } else {
            console.warn("Unexpected create/update prospect response:", r);
          }
        })
        .catch(err => console.error("frappe.call error (create/update prospect):", err));
    } catch (err) {
      console.error("Exception while calling create/update prospect:", err);
    }
  });
}

  // --------------------------
  // Helper: Normalize and extract list from various response shapes
  // --------------------------
  function extractListFromResponse(r) {
    // log raw response for debugging
    // (you can remove this log after debugging)
    console.log("frappe response raw:", r);

    if (!r) return [];
    const m = r.message;
    if (!m) return [];

    if (Array.isArray(m)) return m;
    if (Array.isArray(m.data)) return m.data;
    if (Array.isArray(m.docs)) return m.docs;
    // sometimes backend wraps in {message: {data: [...]}} or similar
    if (m && typeof m === "object") {
      if (Array.isArray(m.message)) return m.message;
      if (Array.isArray(m.results)) return m.results;
      // check nested known keys
      for (const key of ["data", "docs", "results", "items"]) {
        if (Array.isArray(m[key])) return m[key];
      }
      // if object is actually a map of records, return values
      const vals = Object.values(m).filter(v => typeof v === "object");
      if (vals.length && Array.isArray(vals[0])) return vals[0]; // first array found
      // if it's an object with numeric keys, convert to array
      const numericVals = Object.keys(m).every(k => /^\d+$/.test(k));
      if (numericVals) return Object.keys(m).map(k => m[k]);
    }
    return [];
  }

  // ----- LOAD ALL LEADS -----
  async function loadLeads() {
    const list = $id("lead-list");
    if (!list) {
      console.error("Element with id 'lead-list' not found in DOM.");
      return;
    }
    list.innerHTML = "<li>Loading leads...</li>";

    try {
      const r = await frappe.call({ method: "my_webapp.api.get_all_leads" });
      // r may be the response object or a promise-resolved value; ensure we handle both
      const leads = extractListFromResponse(r);
      list.innerHTML = "";
      if (leads && leads.length > 0) {
        leads.forEach(lead => {
          const first = lead.first_name || lead.firstName || lead.firstname || "";
          const last = lead.last_name || lead.lastName || lead.lastname || "";
          const id = lead.name || lead.id || "";
          const li = document.createElement("li");
          li.textContent = `${(first + " " + last).trim()}` + (id ? ` (${id})` : "");
          if (id) {
            li.style.cursor = "pointer";
            li.addEventListener("click", () => loadLeadDetails(id));
          }
          list.appendChild(li);
        });
      } else {
        list.innerHTML = "<li>No leads found</li>";
      }
    } catch (err) {
      console.error("Error fetching leads:", err);
      list.innerHTML = "<li>Error loading leads</li>";
    }
  }

  // ----- LOAD ALL PROSPECTS -----
  async function loadProspects() {
    const list = $id("prospect-list");
    if (!list) {
      console.error("Element with id 'prospect-list' not found in DOM.");
      return;
    }
    list.innerHTML = "<li>Loading prospects...</li>";

    try {
      const r = await frappe.call({ method: "my_webapp.api.get_all_prospects" });
      const prospects = extractListFromResponse(r);
      list.innerHTML = "";
      if (prospects && prospects.length > 0) {
        prospects.forEach(p => {
          const name = p.name || p.id || "";
          const status = p.status || "";
          const leadRef = p.lead || "";
          const display = `${leadRef ? leadRef + " - " : ""}${status ? status + " - " : ""}${name}`.replace(/\s-\s$/, "");
          const li = document.createElement("li");
          li.textContent = display;
          if (name) {
            li.style.cursor = "pointer";
            li.addEventListener("click", () => loadProspectDetails(name));
          }
          list.appendChild(li);
        });
      } else {
        list.innerHTML = "<li>No prospects found</li>";
      }
    } catch (err) {
      console.error("Error fetching prospects:", err);
      list.innerHTML = "<li>Error loading prospects</li>";
    }
  }

  // ----- LOAD SINGLE LEAD DETAILS -----
  function loadLeadDetails(name) {
    try {
      frappe.call({ method: "my_webapp.api.get_lead_details", args: { name } })
        .then(function (r) {
          console.log("frappe response (lead details):", r);
          if (r && r.message) {
            const doc = r.message;
            Object.keys(doc).forEach(k => {
              const el = document.querySelector(`#lead-form [name='${k}']`);
              if (el) el.value = doc[k];
            });
            if (leadFormContainer) leadFormContainer.style.display = "block";
            if (prospectFormContainer) prospectFormContainer.style.display = "none";
            if (leadNameField) leadNameField.value = doc.name || name;
            if (convertSection) convertSection.style.display = (doc.status === "Converted") ? "block" : "none";
          } else {
            console.warn("No lead details returned for:", name, r);
          }
        })
        .catch(err => console.error("frappe.call error (lead details):", err));
    } catch (err) {
      console.error("Exception in loadLeadDetails:", err);
    }
  }

  // ----- LOAD SINGLE PROSPECT DETAILS -----
  function loadProspectDetails(name) {
    try {
      frappe.call({ method: "my_webapp.api.get_prospect_details", args: { name } })
        .then(function (r) {
          console.log("frappe response (prospect details):", r);
          if (r && r.message) {
            const doc = r.message;
            Object.keys(doc).forEach(k => {
              const el = document.querySelector(`#prospect-form [name='${k}']`);
              if (el) el.value = doc[k];
            });
            if (prospectFormContainer) prospectFormContainer.style.display = "block";
            if (leadFormContainer) leadFormContainer.style.display = "none";
          } else {
            console.warn("No prospect details returned for:", name, r);
          }
        })
        .catch(err => console.error("frappe.call error (prospect details):", err));
    } catch (err) {
      console.error("Exception in loadProspectDetails:", err);
    }
  }

  // ----- POPULATE LEAD DROPDOWN IN PROSPECT FORM -----
  async function populateLeadDropdown() {
    if (!leadDropdown) {
      console.warn("Lead dropdown element (#lead-dropdown) not found.");
      return;
    }
    leadDropdown.innerHTML = "<option>Loading...</option>";

    try {
      const r = await frappe.call({ method: "my_webapp.api.get_all_leads" });
      const leads = extractListFromResponse(r);
      leadDropdown.innerHTML = "";
      if (leads && leads.length > 0) {
        leads.forEach(lead => {
          const opt = document.createElement("option");
          opt.value = lead.name || lead.id || "";
          const first = lead.first_name || lead.firstName || "";
          const last = lead.last_name || lead.lastName || "";
          opt.textContent = `${(first + " " + last).trim()}` + (lead.name ? ` (${lead.name})` : "");
          leadDropdown.appendChild(opt);
        });
      } else {
        leadDropdown.innerHTML = "<option value=''>No leads</option>";
      }
    } catch (err) {
      console.error("Error populating lead dropdown:", err);
      leadDropdown.innerHTML = "<option value=''>Error</option>";
    }
  }

  // ----- INITIAL LOAD -----
  // run initial loads but don't block UI if any fail
  loadLeads();
  loadProspects();
  populateLeadDropdown();
});

