/* ======================================================
  PDF.js Setup
====================================================== */
pdfjsLib.GlobalWorkerOptions.workerSrc =
    "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/2.16.105/pdf.worker.min.js";

const params = new URLSearchParams(window.location.search);
const docname = params.get("doc");

if (!docname) {
    frappe.msgprint("Invalid signing link");
    throw "Missing docname";
}

/* ======================================================
  Load PDF
====================================================== */
frappe.call({
    method: "get_sign_document",
    args: { docname },
    callback(r) {

        if (r.message && r.message.already_signed === 1) {
            document.body.innerHTML = `
                <div style="
                    display:flex;
                    justify-content:center;
                    align-items:center;
                    height:100vh;
                    font-size:28px;
                    font-weight:600;
                    color:green;
                    text-align:center;
                ">
                    This document is already signed.
                </div>`;
            return;
        }

        if (!r.message || !r.message.pdf_url) {
            frappe.msgprint("Unable to load document");
            return;
        }

         // ✅ JUST STORE — NO CALCULATION
storedSignaturePosition = {
    page: Number(r.message.signature_page) - 1,   // 0-based
    x: Number(r.message.signature_x),
    y: Number(r.message.signature_y),
    width: Number(r.message.signature_width),
    height: Number(r.message.signature_height),
    canvas_width: Number(r.message.canvas_width),
    canvas_height: Number(r.message.canvas_height)
};


        console.log("Signature Position:", storedSignaturePosition);
        renderPDF(r.message.pdf_url);
    }
});

/* ======================================================
  Render PDF
====================================================== */
function renderPDF(pdfApiUrl) {
    const container = document.getElementById("pdf-container");
    container.innerHTML = "";

    fetch(pdfApiUrl)
        .then(res => res.arrayBuffer())
        .then(buffer => pdfjsLib.getDocument({ data: new Uint8Array(buffer) }).promise)
        .then(pdf => {
            for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
                pdf.getPage(pageNum).then(page => {
                    const viewport = page.getViewport({ scale: 1.5 });

                    const wrapper = document.createElement("div");
                    wrapper.className = "pdf-page";
                    wrapper.style.position = "relative";

                    const canvas = document.createElement("canvas");
                    canvas.width = viewport.width;
                    canvas.height = viewport.height;

                    page.render({ canvasContext: canvas.getContext("2d"), viewport });

                    wrapper.appendChild(canvas);
                    container.appendChild(wrapper);
                });
            }
        });
}

/* ======================================================
  Signature Pad
====================================================== */
const sigCanvas = document.getElementById("signature-pad");
const sigCtx = sigCanvas.getContext("2d");
let drawing = false;

sigCanvas.onmousedown = e => {
    drawing = true;
    sigCtx.beginPath();
    sigCtx.moveTo(e.offsetX, e.offsetY);
};

sigCanvas.onmousemove = e => {
    if (!drawing) return;
    sigCtx.lineTo(e.offsetX, e.offsetY);
    sigCtx.stroke();
};

sigCanvas.onmouseup = sigCanvas.onmouseleave = () => drawing = false;

document.getElementById("clear").onclick = () => {
    sigCtx.clearRect(0, 0, sigCanvas.width, sigCanvas.height);
};

