document.getElementById("signature-upload").addEventListener("change", function (e) {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = function () {
        const img = document.getElementById("signature-preview");

        // 🔑 STORE BASE64 PERMANENTLY
        uploadedSignatureBase64 = reader.result;

        // Sidebar preview
        img.src = reader.result;
        img.style.display = "block";
        img.style.position = "static";
        img.style.cursor = "grab";

        enableDragFromSidebar(img);
    };
    reader.readAsDataURL(file);
});








function enableDragFromSidebar(sidebarImg) {
    sidebarImg.onmousedown = function (e) {
        e.preventDefault();

        // ✅ CLONE IMAGE FOR PDF
        const pdfImg = sidebarImg.cloneNode(true);
        pdfImg.style.position = "absolute";
        pdfImg.style.zIndex = "9999";
        pdfImg.style.cursor = "move";

        const pdfContainer = document.getElementById("pdf-container");
        pdfContainer.appendChild(pdfImg);

        makeDraggable(pdfImg);
    };
}



function makeDraggable(img) {
    let dragging = false;
    let offsetX = 0;
    let offsetY = 0;

    img.onmousedown = function (e) {
        dragging = true;

        const rect = img.getBoundingClientRect();
        offsetX = e.clientX - rect.left;
        offsetY = e.clientY - rect.top;

        e.preventDefault();
    };

    document.onmousemove = function (e) {
        if (!dragging) return;

        const pdfRect = document.getElementById("pdf-container").getBoundingClientRect();

        img.style.left = (e.clientX - pdfRect.left - offsetX) + "px";
        img.style.top = (e.clientY - pdfRect.top - offsetY) + "px";
    };

    document.onmouseup = function () {
        if (!dragging) return;
        dragging = false;
        saveSignaturePosition(img);
    };
}






/* ======================================================
  Save Signature Position
====================================================== */
function saveSignaturePosition(img) {
    const pages = document.querySelectorAll(".pdf-page");

    pages.forEach((pageDiv, index) => {
        const rect = pageDiv.getBoundingClientRect();
        const imgRect = img.getBoundingClientRect();

        if (
            imgRect.left >= rect.left &&
            imgRect.right <= rect.right &&
            imgRect.top >= rect.top &&
            imgRect.bottom <= rect.bottom
        ) {
            const canvas = pageDiv.querySelector("canvas");

            placedSignature = {
                image: img.src,
                page: index,
                x: imgRect.left - rect.left,
                y: imgRect.top - rect.top,
                width: img.width,
                height: img.height,
                canvas_width: canvas.width,
                canvas_height: canvas.height
            };

            console.log("Signature placed:", placedSignature);
        }
    });
}



// Finish and Download

document.getElementById("finish").onclick = () => {

    if (!storedSignaturePosition) {
        frappe.msgprint("Signature position is not configured for this document");
        return;
    }

    const requiredFields = [
        "page", "x", "y",
        "width", "height",
        "canvas_width", "canvas_height"
    ];

    for (const field of requiredFields) {
        if (
            storedSignaturePosition[field] === undefined ||
            storedSignaturePosition[field] === null ||
            isNaN(storedSignaturePosition[field])
        ) {
            frappe.msgprint(`Missing signature position field: ${field}`);
            return;
        }
    }

    let signatureImage = null;

    // ==============================
    // PRIORITY 1: UPLOADED PNG
    // ==============================
    if (uploadedSignatureBase64) {
        signatureImage = uploadedSignatureBase64;
    }

    // ==============================
    // PRIORITY 2: DRAWN SIGNATURE
    // ==============================
    else {
        const drawn = sigCanvas.toDataURL("image/png");
        if (drawn.length < 1000) {
            frappe.msgprint("Please sign before submitting");
            return;
        }
        signatureImage = drawn;
    }

    // ==============================
    // ALWAYS USE RECORD POSITION
    // ==============================
    const signaturesToSend = [{
        image: signatureImage,
        page: storedSignaturePosition.page,
        x: storedSignaturePosition.x,
        y: storedSignaturePosition.y,
        width: storedSignaturePosition.width,
        height: storedSignaturePosition.height,
        canvas_width: storedSignaturePosition.canvas_width,
        canvas_height: storedSignaturePosition.canvas_height
    }];

    frappe.call({
        method: "my_webapp.api.finalize_signature",
        args: {
            docname: docname,
            signatures: JSON.stringify(signaturesToSend),
            mode: "dragdrop"
        },
        callback(r) {

            let pdfUrl = null;

            if (typeof r.message === "string") {
                pdfUrl = r.message;
            } else if (r.message?.signed_pdf) {
                pdfUrl = r.message.signed_pdf;
            } else if (r.message?.file_url) {
                pdfUrl = r.message.file_url;
            }

            if (!pdfUrl) {
                console.error("Finalize response:", r.message);
                frappe.msgprint("Signed PDF URL not returned from server");
                return;
            }

            // ✅ Download PDF
            downloadFile(pdfUrl);

            // ✅ Remove all UI + success message
            document.body.innerHTML = `
                <div style="
                    height:100vh;
                    display:flex;
                    align-items:center;
                    justify-content:center;
                    font-size:26px;
                    color:green;
                    font-weight:bold;
                    text-align:center;
                ">
                    Thank you! <br><br>
                    Your response is submitted successfully.
                </div>
            `;
        }
    });
};








/* ======================================================
  Download Helper
====================================================== */
function downloadFile(url) {
    const a = document.createElement("a");
    a.href = url;
    a.download = "";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
}
